+
+func (c *Client) GetShow(ctx context.Context, id string) (Item, error) {
+	var raw showItem
+	if err := c.get(ctx, "/shows/"+id, url.Values{}, &raw); err != nil {
+		return Item{}, err
+	}
+	return mapShow(raw), nil
